import React, { useEffect, useState } from "react";

export default function Dashboard() {
  const [stats, setStats] = useState({});

  useEffect(() => {
    fetch("http://localhost:8086/tasks/stats")
      .then(res => res.json())
      .then(setStats);
  }, []);

  return (
    <div className="mb-6 p-6 rounded-2xl shadow-xl bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 text-white">

      {/* Title */}
      <h2 className="text-2xl font-bold mb-4">📊 Task Dashboard</h2>

      {/* Stats Grid */}
      <div className="grid grid-cols-3 gap-4 mb-5">

        <div className="bg-white/20 p-4 rounded-xl text-center backdrop-blur">
          <p className="text-sm opacity-80">Total</p>
          <p className="text-2xl font-bold">{stats.total ?? 0}</p>
        </div>

        <div className="bg-white/20 p-4 rounded-xl text-center backdrop-blur">
          <p className="text-sm opacity-80">Completed</p>
          <p className="text-2xl font-bold">{stats.completed ?? 0}</p>
        </div>

        <div className="bg-white/20 p-4 rounded-xl text-center backdrop-blur">
          <p className="text-sm opacity-80">Pending</p>
          <p className="text-2xl font-bold">{stats.pending ?? 0}</p>
        </div>

      </div>

      {/* Progress Section */}
      <div>
        <div className="flex justify-between text-sm mb-1">
          <span>Progress</span>
          <span>{stats.progress ?? 0}%</span>
        </div>

        <div className="w-full bg-white/20 rounded-full h-3 overflow-hidden">
          <div
            className="h-3 rounded-full bg-green-400 transition-all duration-500"
            style={{ width: `${stats.progress ?? 0}%` }}
          />
        </div>
      </div>
    </div>
  );
}
